	input lb_clk,
	input [7:0] net_idata,
	output [7:0] net_odata,
`ifdef QF2
	input rx_stb,
	input rx_end,
	input tx_stb,
	output tx_rdy,
	output tx_end,
`else
	input raw_l,
	input raw_s,
	input [10:0] len_c,
	output [7:0] n_lat_expose,  // work around a limitation in Verilator
`endif
	output lb_error,
