3	// Experiment to fix CDC in lcls2_llrf application_top.v
4	// Preload a 16x32 dpram with the output of a mux running in the app_clk domain
5	// Do that in response to a lb_prefill request, that has to be provided
6	// some 300 ns before the actual lb_clk read cycles.
7	// In our network-gatewayed localbus context, that would come at
8	// the beginning of a packet.  Test versions of both badger/mem_gateway
9	// and bmb7_kintex/jxj_gate have such an output.
10	
11	module jit_rad_gateway #(
12		parameter dw = 32,
13		parameter passthrough = 1
14	) (
15		// basic localbus hookup
16		input lb_clk,
17		input [3:0] lb_addr,
18		input lb_strobe,
19		output [dw-1:0] lb_odata,
20		// control
21		input lb_prefill,
22		output lb_error,
23		input app_clk,
24		// to application mux
25		output xfer_clk,
26		output xfer_snap,
27		output xfer_strobe,
28		output [3:0] xfer_addr,
29		input [dw-1:0] xfer_odata
30	);
31	
32	generate if (passthrough) begin : thru
33		// Zero-footprint option, that doesn't solve CDC problems
34		assign xfer_clk = lb_clk;
35		assign xfer_strobe = lb_strobe;
36		assign xfer_addr = lb_addr;
37		assign lb_odata = xfer_odata;
38		assign lb_error = 0;
39		assign xfer_snap = 1;  // doesn't really work
40	end else begin : buffer
41		// Actually separate lb_clk domain from xfer_clk domain
42		// Takes a bit more than 17 xfer_clk cycles to fill the
43		// dpram with a snapshot of the mux results, after which
44		// the lb_clk read process can just grab data from the dpram.
45		assign xfer_clk = app_clk;
46		wire app_prefill;
47		flag_xdomain trig(
48			.clk1(lb_clk), .flagin_clk1(lb_prefill),
49			.clk2(app_clk), .flagout_clk2(app_prefill));
50		assign xfer_snap = app_prefill;
51		//
52		reg buff_we=0;
53		reg [3:0] addr1=0, addr2=0;
54		wire app_running = |addr1;
55		reg app_running_r=0;
56		assign xfer_strobe = app_prefill | app_running;
57		always @(posedge app_clk) begin
58			if (app_prefill | app_running) addr1 <= addr1 + 1;
59			buff_we <= xfer_strobe;
60			addr2 <= addr1;
61			app_running_r <= app_running;
62		end
63		assign xfer_addr = addr1;
64		dpram #(.aw(4), .dw(dw)) buff(
65			.clka(app_clk), .addra(addr2), .wena(buff_we), .dina(xfer_odata),
66			.clkb(lb_clk), .addrb(lb_addr), .doutb(lb_odata));
67		//
68		reg lb_pending=0, lb_running=0;
69		always @(posedge lb_clk) lb_running <= app_running_r;  // CDC
70		always @(posedge lb_clk) begin
71			if (lb_prefill) lb_pending <= 1;
72			if (lb_running) lb_pending <= 0;
73		end
74		assign lb_error = (lb_prefill | lb_strobe) & (lb_pending | lb_running);
75	end endgenerate
76	
77	endmodule
